   367→
   368→function updateStats() {
   369→  const total = allOrders.length;
   370→  const revenue = allOrders.filter(o=>o.status!=='Cancelled').reduce((s,o)=>s+o.total,0);
   371→  const pending = allOrders.filter(o=>o.status==='Pending').length;
   372→  const delivered = allOrders.filter(o=>o.status==='Delivered').length;
   373→  document.getElementById('statTotal').textContent = total;
   374→  document.getElementById('statRevenue').textContent = '₱'+revenue.toLocaleString();
   375→  document.getElementById('statPending').textContent = pending;
   376→  document.getElementById('statDelivered').textContent = delivered;
