   385→
   386→function renderTable() {
   387→  const search = document.getElementById('searchInput').value.toLowerCase();
   388→  let filtered = allOrders;
   389→  if (currentFilter !== 'all') filtered = filtered.filter(o=>o.status===currentFilter);
