   391→    o.customer.name.toLowerCase().includes(search) ||
   392→    o.id.toLowerCase().includes(search) ||
   393→    o.customer.phone.includes(search)
   394→  );
   395→
   396→  document.getElementById('orderCount').textContent = filtered.length + ' order' + (filtered.length!==1?'s':'');
   397→  const tbody = document.getElementById('ordersBody');
