   428→function formatTime(iso) {
   429→  if (!iso) return '—';
   430→  const d = new Date(iso);
   431→  const now = new Date();
   432→  const diff = Math.floor((now - d) / 1000);
   433→  if (diff < 60) return 'Just now';
   434→  if (diff < 3600) return Math.floor(diff/60) + 'm ago';
   435→  if (diff < 86400) return Math.floor(diff/3600) + 'h ago';
   436→  return d.toLocaleDateString('en-PH', { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' });
   437→}
